import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly handle user input by encoding it before outputting to a web page
        try {
            String encodedInput = ESAPI.encoder().encodeForHTML(userInput);
            System.out.println("<p>User Input: " + encodedInput + "</p>");
        } catch (EncodingException e) {
            System.err.println("Error encoding user input: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
